mapper.select:
/*  on.standard.system.user.selectUserRoleList */
SELECT AUTH_ID    userAuth
  FROM STB_M_AUTH_USER_MNG
 WHERE USER_ID = #{userId}

mapper.update:
/*  on.standard.system.user.updUserFinalLogin */
UPDATE STB_B_USER_MNG
   SET LST_LOGIN_DT = CURTIME()
     , PSWD_FAIL_CNT = 0
 WHERE USER_ID =  #{userId}

mapper.select:
/*  on.standard.system.user.selectUserIdDuplChk */
SELECT CASE WHEN COUNT(*)  = 0 THEN 'ABLE' ELSE 'NOT_ABLE' END isAble
FROM STB_B_USER_MNG
WHERE USER_ID = #{userId}

mapper.update:
/*  on.standard.system.user.updateUserMng */
 UPDATE STB_B_USER_MNG
    SET USER_ID = #{userId}

     , USER_PSWD = #{userPswd}


    , USER_KOR_NM = #{userKorNm}


    , USER_ENG_NM = #{userEngNm}


    , MOBILE_NO = #{mobileNo}


    , EMAIL_ADDR = #{emailAddr}


        , ZIP_NO = #{zipNo}


        , HOME_ADDR = #{homeAddr}


        , HOME_ADDR_DTLS = #{homeAddrDtls}


        , BLON_NM = #{blonNm}


        , FAX_NO = #{faxNo}


        , JGRP_CD = #{jgrpCd}


        , JRNK_CD = #{jrnkCd}

   WHERE USER_ID = #{userId}

/*  on.standard.system.user.updateAuthUserMng */
UPDATE STB_M_AUTH_USER_MNG
   SET USE_YN = 'Y'
    , AUTH_ID = #{userAuth}
WHERE AUTH_ID = #{preUserAuth}
  AND USER_ID = #{userId}

